class Solution {
public:
    int minChanges(int n, int k) {
        int changes = 0;
        while (n != k) {
            if ((n & 1) != (k & 1)) {
                n ^= 1;
                changes++;
            }
            n >>= 1;
            k >>= 1;
        }
        return changes;
    }
};
```
